fn main() {
    // Demonstrate usage
    println!("=== FfiBuffer Demo ===\n");

    // Create a buffer with custom alignment
    let mut buffer = FfiBuffer::new(1024, 16).expect("Failed to allocate buffer");
    println!(
        "Created buffer: capacity={}, alignment=16, ptr={:p}",
        buffer.capacity(),
        buffer.as_ptr()
    );

    // Write some data
    buffer.append(b"Hello from Rust!").expect("Write failed");
    buffer
        .append(b" More data here.")
        .expect("Append failed");
    println!("Written {} bytes: {:?}", buffer.len(), buffer.as_slice());

    // Read back specific portions
    let hello = buffer.read_at(0, 5).expect("Read failed");
    println!("First 5 bytes: {:?}", std::str::from_utf8(hello).unwrap());

    // Demonstrate FFI transfer
    let (ptr, len, cap, layout) = create_ffi_buffer(b"FFI payload data", 8).unwrap();
    println!(
        "\nFFI buffer created: ptr={:p}, len={}, cap={}",
        ptr, len, cap
    );

    // Simulate C code reading the data
    let ffi_data = unsafe { std::slice::from_raw_parts(ptr, len) };
    println!(
        "FFI data: {:?}",
        std::str::from_utf8(ffi_data).unwrap()
    );

    // Clean up FFI buffer
    unsafe {
        free_ffi_buffer(ptr, layout);
    }
    println!("FFI buffer freed.");

    // Demonstrate C-compatible API
    println!("\n=== C-compatible API Demo ===");
    let c_buf = buffer_create(512);
    let msg = b"Message via C API";
    buffer_write(c_buf, msg.as_ptr(), msg.len());
    let c_len = buffer_get_len(c_buf);
    let c_ptr = buffer_get_ptr(c_buf);
    let c_slice = unsafe { std::slice::from_raw_parts(c_ptr, c_len) };
    println!("C API result: {:?}", std::str::from_utf8(c_slice).unwrap());
    buffer_destroy(c_buf);
    println!("C buffer destroyed.");

    println!("\nAll operations completed successfully!");
}